     9→const JWT_SECRET = 'test-jwt-secret-at-least-32-characters-long';
    10→const SESSION_TTL = 30 * 24 * 60 * 60;
    11→
    12→export interface ITestUser {
    13→	_id: string;
    14→	email: string;
    15→	name: string | null;
    16→	avatar_url: string | null;
