   164→				`linking_token:${linkingToken}`,
   165→				JSON.stringify(linkingTokenData),
   166→				'EX',
   167→				LINKING_TOKEN_TTL,
   168→			);
   169→
   170→			return { type: 'linking_required', linkingToken };
   171→		}
   172→
   173→		const newUser = await this.userService.create({
   174→			data: {
   175→				email: profile.email,
   176→				name: profile.name,
   177→				avatar_url: profile.avatar_url,
   178→			},
   179→		});
   180→
   181→		await this.oauthAccountService.create({
   182→			data: {
   183→				user_id: newUser._id,
   184→				provider: profile.provider,
   185→				provider_id: profile.provider_id,
   186→				email: profile.email || null,
   187→				access_token: accessToken,
   188→			},
   189→		});
   190→
   191→		const authCode = randomBytes(32).toString('hex');
   192→		const authCodeData: IAuthCode = {
   193→			user_id: newUser._id,
   194→			session_id: randomUUID(),
   195→		};
   196→
   197→		await this.redisWrite.set(
   198→			`auth_code:${authCode}`,
   199→			JSON.stringify(authCodeData),
   200→			'EX',
   201→			AUTH_CODE_TTL,
   202→		);
   203→
   204→		return { type: 'auth_code', code: authCode };
   205→	}
