   207→	async exchangeCode({
   208→		code,
   209→		ip,
   210→		userAgent,
   211→		provider,
   212→	}: {
   213→		code: string;
   214→		ip: string;
   215→		userAgent: string;
   216→		provider: 'github' | 'google';
   217→	}): Promise<{ accessToken: string; refreshToken: string }> {
   218→		this.logger.log('Exchanging auth code for tokens');
   219→
   220→		const raw = await this.redisWrite.getdel(`auth_code:${code}`);
   221→
   222→		if (!raw) {
   223→			throw new UnauthorizedException('Invalid or expired auth code');
   224→		}
   225→
   226→		const authCodeData = JSON.parse(raw) as IAuthCode;
   227→		const { user_id, session_id } = authCodeData;
   228→
   229→		const memberships = await this.companyMemberService.findByUserId({ userId: user_id });
   230→		const firstMembership = memberships[0] ?? null;
   231→
   232→		const refreshToken = randomUUID();
   233→		const now = new Date().toISOString();
   234→
   235→		const session: ISession = {
   236→			user_id,
   237→			session_id,
   238→			role: firstMembership ? firstMembership.role : null,
   239→			company_id: firstMembership ? firstMembership.company_id : null,
   240→			provider,
   241→			ip,
   242→			user_agent: userAgent,
   243→			created_at: now,
   244→			last_active: now,
   245→		};
   246→
   247→		await this.sessionService.createSession({ session, refreshToken });
   248→
   249→		const expiry = this.configService.get<number>({
   250→			key: JWT_ACCESS_TOKEN_EXPIRY,
   251→			converter: Number,
   252→		});
   253→
   254→		const payload: IJwtPayload = {
   255→			user_id,
   256→			session_id,
   257→			role: session.role,
   258→			company_id: session.company_id,
   259→		};
   260→
   261→		const accessToken = await this.jwtService.signAsync(payload, {
   262→			expiresIn: expiry,
   263→		});
   264→
   265→		return { accessToken, refreshToken };
   266→	}
   267→
   268→	async refreshTokens({
   269→		refreshToken,
   270→	}: {
   271→		refreshToken: string;
   272→	}): Promise<{ accessToken: string; refreshToken: string }> {
   273→		this.logger.log('Refreshing tokens');
   274→
   275→		const tokenData = await this.sessionService.validateRefreshToken({ refreshToken });
   276→
   277→		if (!tokenData) {
   278→			const reuseData = await this.sessionService.detectRefreshTokenReuse({
   279→				refreshToken,
   280→			});
   281→
   282→			if (reuseData) {
   283→				await this.sessionService.destroySession({
   284→					userId: reuseData.user_id,
   285→					sessionId: reuseData.session_id,
   286→				});
   287→			}
   288→
   289→			throw new UnauthorizedException('Invalid or expired refresh token');
   290→		}
   291→
   292→		const { user_id, session_id } = tokenData;
   293→
   294→		const session = await this.sessionService.getSession({
   295→			userId: user_id,
   296→			sessionId: session_id,
   297→		});
   298→
   299→		if (!session) {
   300→			throw new UnauthorizedException('Session not found');
   301→		}
   302→
   303→		const newRefreshToken = await this.sessionService.rotateRefreshToken({
   304→			oldToken: refreshToken,
   305→			session,
   306→		});
   307→
   308→		await this.sessionService.updateLastActive({
   309→			userId: user_id,
   310→			sessionId: session_id,
   311→		});
   312→
   313→		const expiry = this.configService.get<number>({
   314→			key: JWT_ACCESS_TOKEN_EXPIRY,
   315→			converter: Number,
   316→		});
   317→
   318→		const payload: IJwtPayload = {
   319→			user_id,
   320→			session_id,
   321→			role: session.role,
   322→			company_id: session.company_id,
   323→		};
   324→
   325→		const accessToken = await this.jwtService.signAsync(payload, {
   326→			expiresIn: expiry,
   327→		});
   328→
   329→		return { accessToken, refreshToken: newRefreshToken };
   330→	}
