   332→	async linkAccount({
   333→		linkingToken,
   334→		userId,
   335→	}: {
   336→		linkingToken: string;
   337→		userId: string;
   338→	}): Promise<void> {
   339→		this.logger.log('Linking OAuth account', { userId });
   340→
   341→		const raw = await this.redisWrite.getdel(`linking_token:${linkingToken}`);
   342→
   343→		if (!raw) {
   344→			throw new UnauthorizedException('Invalid or expired linking token');
   345→		}
   346→
   347→		const tokenData = JSON.parse(raw) as ILinkingToken;
   348→
   349→		if (tokenData.existing_user_id !== userId) {
   350→			throw new UnauthorizedException('Linking token does not match user');
   351→		}
   352→
   353→		await this.oauthAccountService.create({
   354→			data: {
   355→				user_id: userId,
   356→				provider: tokenData.provider,
   357→				provider_id: tokenData.provider_id,
   358→				email: tokenData.provider_email || null,
   359→				access_token: tokenData.access_token,
   360→			},
   361→		});
   362→	}
