    33→
    34→	private decryptToken({ row }: { row: IOAuthAccountBase }): IOAuthAccountBase {
    35→		if (row.access_token === null) {
    36→			return row;
    37→		}
    38→		const key = this.getEncryptionKey();
    39→		return { ...row, access_token: decrypt({ ciphertext: row.access_token, key }) };
    40→	}
