    42→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
    43→		return errors
    44→			.map(
    45→				(error) =>
    46→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
    47→			)
    48→			.join('; ');
    49→	}
