    56→		providerId: IOAuthAccountBase['provider_id'];
    57→	}): Promise<IOAuthAccountBase | null> {
    58→		try {
    59→			const result = await this.knexRead<IOAuthAccountBase>(this.tableName)
    60→				.where({ provider, provider_id: providerId })
    61→				.whereNull('deleted_at')
    62→				.first();
    63→
    64→			if (!result) {
