    73→				);
    74→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
    75→			}
    76→
    77→			return this.decryptToken({ row: result });
    78→		} catch (error) {
    79→			this.logger.error(
    80→				`Failed to find oauth account by provider ${provider} and providerId ${providerId}: ${(error as Error).message}`,
    81→			);
    82→			throw error;
    83→		}
    84→	}
